const d = $input.first().json.body || $input.first().json;
const risk = d.risk || {};
const sailing = d.sailing;

let msg = '🌊 *Resumen diario — ' + (d.sector || 'MeteoMapGal') + '*\n';

const date = new Date(d.timestamp || Date.now());
const days = ['domingo','lunes','martes','miércoles','jueves','viernes','sábado'];
const months = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
msg += '📅 ' + days[date.getDay()] + ' ' + date.getDate() + ' de ' + months[date.getMonth()] + '\n\n';

// Risk level
const riskEmoji = risk.severity === 'critical' ? '🔴' : risk.severity === 'high' ? '🟠' : risk.severity === 'moderate' ? '🟡' : '🟢';
msg += riskEmoji + ' Riesgo: ' + (risk.severity || 'low').toUpperCase() + ' (' + (risk.score || 0) + '/100)\n';

if ((risk.activeCount || 0) > 0) {
  msg += '⚠️ ' + risk.activeCount + ' alerta(s) activa(s)\n';
}

// Alerts
if (d.alerts && d.alerts.length > 0) {
  msg += '\n*Alertas:*\n';
  for (const a of d.alerts) {
    msg += '• ' + a.title + '\n';
  }
}

// Best sailing window
if (sailing) {
  const startH = new Date(sailing.start);
  const endH = new Date(sailing.end);
  const fmt = (dt) => dt.getHours().toString().padStart(2,'0') + ':' + dt.getMinutes().toString().padStart(2,'0');
  msg += '\n⛵ *Mejor ventana:* ' + sailing.spot + '\n';
  msg += '🕐 ' + fmt(startH) + ' — ' + fmt(endH) + '\n';
  msg += '💨 ' + sailing.avgWindKt + 'kt · ' + sailing.verdict.toUpperCase() + '\n';
} else {
  msg += '\n⛵ Sin ventana de navegación clara hoy\n';
}

msg += '\n_meteomapgal.navia3d.com_';

return [{ json: { text: msg, chatId: '160912482' } }];
